const raw = $input.first().json || {};
const files = Array.isArray(raw.files) ? raw.files.map(String) : String(raw.files || '').split(/\r?\n|,/).map(s => s.trim()).filter(Boolean);
const diff = String(raw.diff || raw.patch || raw.conteudo || '').trim();
const title = String(raw.title || raw.titulo || raw.message || 'commit FabioOS').trim();
const source = String(raw.source || raw.origem || 'n8n').trim();
const requestId = raw.request_id || `safe_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
return [{ json: {
  request_id: requestId,
  received_at: new Date().toISOString(),
  title,
  source,
  files,
  diff,
  diff_lines: diff ? diff.split(/\r?\n/).length : 0,
  status: 'normalized'
}}];

const item = $input.first().json;
const patterns = [
  {name: 'openai_key', re: /sk-[A-Za-z0-9._-]{16,}/i, severity: 'alto'},
  {name: 'github_token', re: /gh[pous]_[A-Za-z0-9._-]{16,}/i, severity: 'alto'},
  {name: 'bearer_token', re: /Bearer\s+[A-Za-z0-9._-]{16,}/i, severity: 'alto'},
  {name: 'api_key_assignment', re: /api[_-]?key\s*[:=]/i, severity: 'medio'},
  {name: 'password_assignment', re: /(password|senha)\s*[:=]/i, severity: 'medio'},
  {name: 'secret_assignment', re: /secret\s*[:=]/i, severity: 'medio'},
  {name: 'env_file', re: /(^|[\/])\.env(\.|$)/i, severity: 'medio'},
  {name: 'private_key', re: /BEGIN\s+(RSA|OPENSSH|EC|PRIVATE)\s+KEY/i, severity: 'alto'}
];
const lines = item.diff ? item.diff.split(/\r?\n/) : [];
const findings = [];
for (let i = 0; i < lines.length; i++) {
  const line = lines[i];
  for (const p of patterns) {
    if (p.re.test(line)) {
      findings.push({line: i + 1, pattern: p.name, severity: p.severity, value_omitted: true});
    }
  }
}
for (const f of item.files) {
  if (/(^|[\/])\.env(\.|$)/i.test(f) || /\.(pem|key|secret)$/i.test(f)) {
    findings.push({file: f, pattern: 'sensitive_filename', severity: 'alto', value_omitted: true});
  }
}
return [{ json: {...item, findings, findings_count: findings.length, status: 'scanned'} }];

const item = $input.first().json;
const hasHigh = item.findings.some(f => f.severity === 'alto');
const hasMedium = item.findings.some(f => f.severity === 'medio');
let decision = 'safe_to_review';
let ok = true;
let severity = 'baixo';
if (hasHigh) { decision = 'blocked'; ok = false; severity = 'alto'; }
else if (hasMedium) { decision = 'needs_human_review'; ok = false; severity = 'medio'; }
const warnings = [];
if (!item.files.length) warnings.push('nenhuma_lista_de_arquivos');
if (!item.diff) warnings.push('sem_diff_para_escanear');
return [{ json: {...item, ok, severity, decision, warnings, status: 'classified'} }];

const item = $input.first().json;
const explicitPaths = item.files.map(f => `git add -- "${f.replace(/"/g, '\\"')}"`);
let type = 'docs';
const joined = item.files.join(' ').toLowerCase();
if (/script|\.py|\.js|\.ts|workflow|n8n/.test(joined)) type = 'feat';
if (/fix|bug|corrigir|hotfix/.test(item.title.toLowerCase())) type = 'fix';
if (/changelog|readme|doc|governanca|contrato/.test(joined)) type = 'docs';
const message = `${type}: ${item.title.toLowerCase().replace(/[^a-z0-9\s:-]/g, '').replace(/\s+/g, ' ').slice(0, 72)}`;
const plan = {
  stage_policy: 'stage_explicit_paths_only',
  never_use: ['git add -A'],
  suggested_stage_commands: explicitPaths,
  suggested_commit_message: message,
  pre_commit_checks: ['git diff --cached --check', 'scan de segredos', 'validacao especifica da frente']
};
return [{ json: {...item, plan, status: 'planned'} }];

const item = $input.first().json;
const audit = {
  request_id: item.request_id,
  received_at: item.received_at,
  files_count: item.files.length,
  diff_lines: item.diff_lines,
  findings_count: item.findings_count,
  severity: item.severity,
  decision: item.decision,
  external_effects: false,
  git_executed: false,
  note: 'Preflight apenas consultivo. Nao faz stage, commit, push ou escrita no vault.'
};
return [{ json: {...item, audit, status: 'ready_to_respond'} }];
